  ('locality-7c9828ae-moex-00259', 'locality-7c9828ae', 'locality-7c9828ae-moex-110-d1a761c9', 'sub-locality-7c9828ae-03', NULL, 'single_choice', '關於特別權力關係，下列敘述何者錯誤？', '["受刑人就監獄處分或其他管理措施，逾越達成監獄行刑目的所必要之範圍，而不法侵害其基本權利且非 顯屬輕微時，應許其得向法院請求救濟", "立法者得考量身分之不同而規範不同之救濟途徑，並得剝奪其向法院請求救濟之權利", "現行對現役軍人採行之軍事審判制度，區分為戰時與平時，前者適用軍事審判法，後者則依據刑事訴訟 法行之", "公務人員就影響其權益之公權力措施，於申訴、再申訴後，仍得按相關措施之性質，依法提起相應之行 政訴訟，請求救濟"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:08+00:00", "source_pdf_sha1": "4cc3d93276fc", "answer_pdf_sha1": "85c740cb7eda", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "405", "s": "0609", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "社會工作"}'::jsonb, NULL),
  ('locality-7c9828ae-moex-00260', 'locality-7c9828ae', 'locality-7c9828ae-moex-110-d1a761c9', 'sub-locality-7c9828ae-03', NULL, 'single_choice', '關於公營造物之敘述，下列何者正確？', '["公營造物在我國法上，大部分具有公法人資格", "公營造物之利用關係，一律為公法法律關係", "公營企業與公營造物，係相同概念", "營造物特別強調者，乃人與物作目的性之結合"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:08+00:00", "source_pdf_sha1": "4cc3d93276fc", "answer_pdf_sha1": "85c740cb7eda", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "405", "s": "0609", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "社會工作"}'::jsonb, NULL),
